// SETUP 요청이 오면 실행되는 함수
void CHYRtsp::ResponseSetup()
{
    // 세션 토큰 생성
    sprintf(this->session, "%08x%08x", this, this);
    //                      ^^^^^^^^^^^^^^^^^^^^^^
    //   this = 이 객체가 메모리(힙)의 어느 주소에 있는지를 나타내는 값
    //   이걸 그냥 16진수 문자열로 만들어서 클라이언트에게 보냄!
}

